INSERT INTO state_grants (id,state_code,grantor_name,donor_line,grant_amount,amount_display,req_no_seed,req_has_seed,req_age_max,req_born_year_min,req_born_year_max,req_zip_income,income_cap,req_zip_set,req_checkbox_labels,note,source_url,sort_order,status) VALUES ('tx_little_texan','TX','New Little Texan Savings Fund (Proposed)','Lt. Gov. Dan Patrick — to be introduced 2027 legislative session',1000,'$1,000 (proposed)',0,0,NULL,NULL,NULL,0,NULL,NULL,NULL,'Lt. Gov. Dan Patrick announced this as a top priority for the January 2027 Texas legislative session: $1,000 from the state invested for every Texas newborn, locked until age 18 for education or approved expenses. Estimated ~$400M/yr; Patrick also intends to pursue a constitutional amendment to make the program permanent. No bill has been filed yet.','https://www.texastribune.org/2025/12/03/dan-patrick-donald-trump-baby-savings-accounts/',10,'pending');
INSERT INTO state_grants (id,state_code,grantor_name,donor_line,grant_amount,amount_display,req_no_seed,req_has_seed,req_age_max,req_born_year_min,req_born_year_max,req_zip_income,income_cap,req_zip_set,req_checkbox_labels,note,source_url,sort_order,status) VALUES ('ok_dream_accounts','OK','Oklahoma Dream Accounts','State of Oklahoma — $12.5M appropriated',250,NULL,0,0,17,NULL,NULL,0,NULL,NULL,NULL,'Oklahoma children under 18 (U.S. citizens with primary residence in OK). Requires family application and verification by the State Treasurer.','https://oklahoma.gov/governor/newsroom/newsroom/2026/building-the-american-dream-governor-stitt-signs-oklahoma-dream-accounts-bill.html',10,'active');
INSERT INTO state_grants (id,state_code,grantor_name,donor_line,grant_amount,amount_display,req_no_seed,req_has_seed,req_age_max,req_born_year_min,req_born_year_max,req_zip_income,income_cap,req_zip_set,req_checkbox_labels,note,source_url,sort_order,status) VALUES ('wi_state_match','WI','State of Wisconsin (Proposed)','Assembly passed Jan 2026 — Senate hearing held 3/5/26',1000,'$1,000 (proposed)',0,0,NULL,2025,2028,0,NULL,NULL,NULL,'Wisconsin Assembly passed a $1,000 state match for children born in WI 2025–2028 (funded at $60M/yr from budget surplus). Bill is awaiting full Senate vote and Governor Evers''s signature — not yet law.','https://wisconsinexaminer.com/2026/01/27/assembly-gop-propose-1000-state-match-for-trump-accounts/',10,'pending');